final:
module verified_Gray_counter(
   input                clk ,
   input                rst_n,

   output reg [7:0]     Q  
);
    reg [7:0] unused_binary;

    always@(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            Q <= 8'b0;
            unused_binary <= 8'b0;
        end else begin
            unused_binary <= unused_binary + 1;
            Q <= (unused_binary >> 1) ^ unused_binary;
        end
    end
endmodule
